  select 'missing_identities' as check_name, e.id, e.display_name, e.normalized_lookup_key, e.equipment_tags, e.movement_pattern, e.qualifier_text, e.metadata from expected_identities e left join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.id is null
  union all
  select 'duplicate_identities' as check_name, i.id, null::text, null::text, null::text[], null::text, null::text, null::jsonb from public.exercise_identities i join expected_identities e on e.id = i.id group by i.id having count(*) > 1
  union all
  select 'wrong_display_name' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.display_name <> e.display_name
  union all
  select 'wrong_normalized_lookup_key' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.normalized_lookup_key <> e.normalized_lookup_key
  union all
  select 'wrong_equipment_tags' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.equipment_tags <> e.equipment_tags
  union all
  select 'wrong_movement_pattern' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.movement_pattern <> e.movement_pattern
  union all
  select 'wrong_qualifier_text' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.qualifier_text <> e.qualifier_text
  union all
  select 'wrong_metadata_json' as check_name, e.* from expected_identities e join public.exercise_identities i on i.id = e.id and i.owner_scope = 'system' where i.metadata <> e.metadata
  union all
  select 'wrong_owner_scope' as check_name, i.id, i.display_name, i.normalized_lookup_key, i.equipment_tags, i.movement_pattern, i.qualifier_text, i.metadata from public.exercise_identities i join expected_identities e on e.id = i.id where i.owner_scope <> 'system'
  union all
  select 'unexpected_user_ownership' as check_name, i.id, i.display_name, i.normalized_lookup_key, i.equipment_tags, i.movement_pattern, i.qualifier_text, i.metadata from public.exercise_identities i join expected_identities e on e.id = i.id where i.owner_user_id is not null
  union all
  select 'inactive_or_superseded_identity' as check_name, i.id, i.display_name, i.normalized_lookup_key, i.equipment_tags, i.movement_pattern, i.qualifier_text, i.metadata from public.exercise_identities i join expected_identities e on e.id = i.id where not i.active or i.superseded_by is not null
  union all
  select 'extra_system_seed_identities' as check_name, i.id, i.display_name, i.normalized_lookup_key, i.equipment_tags, i.movement_pattern, i.qualifier_text, i.metadata from public.exercise_identities i left join expected_identities e on e.id = i.id where i.owner_scope = 'system' and e.id is null
)
select * from identity_findings order by check_name, id;

