), alias_findings as (
  select 'missing_aliases' as check_name, e.exercise_identity_id, e.alias, e.normalized_lookup_key from expected_aliases e left join public.exercise_aliases a on a.normalized_lookup_key = e.normalized_lookup_key and a.owner_scope = 'system' and a.reviewed where a.id is null
  union all
  select 'aliases_targeting_wrong_identity' as check_name, e.exercise_identity_id, e.alias, e.normalized_lookup_key from expected_aliases e join public.exercise_aliases a on a.normalized_lookup_key = e.normalized_lookup_key and a.owner_scope = 'system' and a.reviewed where a.exercise_identity_id <> e.exercise_identity_id
  union all
  select 'duplicate_normalized_aliases' as check_name, min(a.exercise_identity_id), min(a.alias), a.normalized_lookup_key from public.exercise_aliases a join expected_aliases e on e.normalized_lookup_key = a.normalized_lookup_key where a.owner_scope = 'system' and a.reviewed group by a.normalized_lookup_key having count(*) > 1
  union all
  select 'alias_to_alias_collisions' as check_name, min(a.exercise_identity_id), min(a.alias), a.normalized_lookup_key from public.exercise_aliases a where a.owner_scope = 'system' and a.reviewed group by a.normalized_lookup_key having count(distinct a.exercise_identity_id) > 1
  union all
  select 'alias_to_canonical_collisions' as check_name, a.exercise_identity_id, a.alias, a.normalized_lookup_key from public.exercise_aliases a join public.exercise_identities i on i.normalized_lookup_key = a.normalized_lookup_key and i.owner_scope = 'system' and i.active and i.id <> a.exercise_identity_id where a.owner_scope = 'system' and a.reviewed
  union all
  select 'aliases_targeting_missing_identities' as check_name, e.exercise_identity_id, e.alias, e.normalized_lookup_key from expected_aliases e left join public.exercise_identities i on i.id = e.exercise_identity_id and i.owner_scope = 'system' where i.id is null
  union all
  select 'aliases_targeting_inactive_or_superseded_identities' as check_name, e.exercise_identity_id, e.alias, e.normalized_lookup_key from expected_aliases e join public.exercise_identities i on i.id = e.exercise_identity_id where not i.active or i.superseded_by is not null
  union all
  select 'non_system_or_unreviewed_rows_occupying_expected_alias_keys' as check_name, a.exercise_identity_id, a.alias, a.normalized_lookup_key from public.exercise_aliases a join expected_aliases e on e.normalized_lookup_key = a.normalized_lookup_key where a.owner_scope <> 'system' or not a.reviewed
  union all
  select 'extra_reviewed_system_aliases' as check_name, a.exercise_identity_id, a.alias, a.normalized_lookup_key from public.exercise_aliases a left join expected_aliases e on e.normalized_lookup_key = a.normalized_lookup_key where a.owner_scope = 'system' and a.reviewed and e.normalized_lookup_key is null
)
select * from alias_findings order by check_name, normalized_lookup_key;

