), idempotency_findings as (
  select 'duplicate_canonical_ids' as check_name, i.id as subject_key, count(*)::text as detail from public.exercise_identities i join expected_identities e on e.id = i.id group by i.id having count(*) > 1
  union all
  select 'conflicting_system_canonical_normalized_names' as check_name, i.normalized_lookup_key, string_agg(i.id, ', ' order by i.id) from public.exercise_identities i join expected_identities e on e.normalized_lookup_key = i.normalized_lookup_key where i.owner_scope = 'system' and i.id <> e.id group by i.normalized_lookup_key
  union all
  select 'reviewed_system_alias_keys_pointing_to_different_targets' as check_name, a.normalized_lookup_key, a.exercise_identity_id from public.exercise_aliases a join expected_aliases e on e.normalized_lookup_key = a.normalized_lookup_key where a.owner_scope = 'system' and a.reviewed and a.exercise_identity_id <> e.exercise_identity_id
  union all
  select 'missing_identity_targets_for_aliases' as check_name, e.normalized_lookup_key, e.exercise_identity_id from expected_aliases e left join public.exercise_identities i on i.id = e.exercise_identity_id and i.owner_scope = 'system' where i.id is null
  union all
  select 'user_owned_rows_occupying_required_identity_ids' as check_name, i.id, i.owner_user_id::text from public.exercise_identities i join expected_identities e on e.id = i.id where i.owner_scope = 'user'
  union all
  select 'user_owned_rows_occupying_required_normalized_keys' as check_name, i.normalized_lookup_key, i.owner_user_id::text from public.exercise_identities i join expected_identities e on e.normalized_lookup_key = i.normalized_lookup_key where i.owner_scope = 'user'
  union all
  select 'inactive_or_superseded_system_targets' as check_name, i.id, coalesce(i.superseded_by, 'inactive') from public.exercise_identities i join expected_identities e on e.id = i.id where i.owner_scope = 'system' and (not i.active or i.superseded_by is not null)
  union all
  select 'alias_canonical_namespace_collisions' as check_name, a.normalized_lookup_key, a.exercise_identity_id from public.exercise_aliases a join public.exercise_identities i on i.normalized_lookup_key = a.normalized_lookup_key and i.owner_scope = 'system' and i.active and i.id <> a.exercise_identity_id where a.owner_scope = 'system' and a.reviewed
)
select * from idempotency_findings order by check_name, subject_key;

